#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
fix_measure_overlay.py — Correctif : apres avoir enregistre une mesure, le SVG
plein ecran des mesures persistees capturait tous les clics et bloquait toute
interaction avec le plan. Desormais seul le petit label est cliquable.
A lancer a la racine du repo (Codespace) :  python3 fix_measure_overlay.py
"""
import base64, json, os, subprocess, sys
FILES=json.loads(r'''{
"src/components/CadViewer.tsx": ""
}''')
def run(*a, check=True):
    print("+"," ".join(a)); return subprocess.run(a, check=check)
def cfg(k): return subprocess.run(["git","config",k],capture_output=True,text=True).stdout.strip()
def main():
    if not os.path.isfile("package.json"): sys.exit("Lance a la racine du repo.")
    for p,b in FILES.items():
        os.makedirs(os.path.dirname(p),exist_ok=True); open(p,"wb").write(base64.b64decode(b)); print("  ecrit:",p)
    print(">>> Verification build..."); 
    if run("npx","next","build",check=False).returncode!=0: sys.exit("!!! build ECHOUE, rien pousse.")
    if not cfg("user.email"): run("git","config","user.email","bilnov-bot@users.noreply.github.com")
    if not cfg("user.name"):  run("git","config","user.name","BILNOV bot")
    run("git","add","-A"); run("git","commit","-m","fix(cad): les mesures enregistrees ne bloquent plus les interactions (SVG overlay pointer-events)")
    run("git","push"); print("\nOK. Push -> Vercel deploie.")
if __name__=="__main__": main()
